#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
using namespace std;
const int N = 405 , M = 405 , INF = 0x3f3f3f3f ;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
struct node{int l,r;}t[N];
int a[N],tot[M][M],pre[M][N],suc[M][N],cnt,ans[N];
int main()
{
//	freopen("in.txt","r",stdin);
	int n=read();rep(1,n,i)a[++cnt]=t[i].l=read(),t[i].r=read(),a[++cnt]=t[i].l+t[i].r,t[i].r=a[cnt];
	sort(a+1,a+cnt+1); int m=unique(a+1,a+cnt+1)-a-1;
	rep(1,m,i)rep(i+1,m,j)rep(1,n,k)tot[i][j]+=(a[i]<=t[k].l&&t[k].r<=a[j]);
	rep(1,n,i)
	{
		rep(1,m,j)if(a[j]==t[i].l){t[i].l=j;break;}
		rep(1,m,j)if(a[j]==t[i].r){t[i].r=j;break;}
	}
	rep(1,m,i){pre[i][0]=tot[1][i];rep(1,n,j){pre[i][j]=-INF;rep(1,i-1,k)pre[i][j]=max(pre[i][j],max(pre[k][j]+tot[k][i],pre[k][max(0,j-tot[k][i])]));}}
	drep(m,1,i){suc[i][0]=tot[i][m];rep(1,n,j){suc[i][j]=-INF;drep(m,i+1,k)suc[i][j]=max(suc[i][j],max(suc[k][j]+tot[i][k],suc[k][max(0,j-tot[i][k])]));}}
	rep(1,n,i)drep(t[i].l,1,j){rep(t[i].r,m,k)
	{
		rep(0,tot[1][j],l){rep(0,tot[k][m],r){ans[i]=max(ans[i],min(l+r+tot[j][k],pre[j][l]+suc[k][r]));if(suc[k][r]<r)break;}if(pre[j][l]<l)break;}
		if(tot[1][j]+tot[k][m]<ans[i]||tot[j][k]>tot[1][j]+tot[k][m])break;
	}	ans[0]=max(ans[0],ans[i]);}
	rep(0,n,i)printf("%d\n",ans[i]);return 0;
}
